Invalid.code:
import { useState } from 'react'
import Input from '@/components/ui/Input'
import Button from '@/components/ui/Button'
import { HiExclamationCircle } from 'react-icons/hi'

const Invalid = () => {
    const [invalid, setInvalid] = useState(false)

    return (
        <div>
            <div className="mb-4">
                <Input
                    invalid={invalid}
                    placeholder="Invalid input"
                    suffix={
                        invalid ? (
                            <HiExclamationCircle className="text-red-500 text-xl" />
                        ) : null
                    }
                />
            </div>
            <div className="mb-4">
                <Input
                    invalid={invalid}
                    placeholder="Invalid text area"
                    textArea
                />
            </div>
            <Button variant="solid" onClick={() => setInvalid(!invalid)}>
                Set {invalid ? 'Valid' : 'Invalid'}
            </Button>
        </div>
    )
}

export default Invalid

PasswordVisible.code:
import { useState } from 'react'
import Input from '@/components/ui/Input'
import { HiOutlineEyeOff, HiOutlineEye } from 'react-icons/hi'
import type { MouseEvent } from 'react'

const PasswordVisible = () => {
    const [pwInputType, setPwInputType] = useState('password')

    const onPasswordVisibleClick = (e: MouseEvent) => {
        e.preventDefault()
        setPwInputType(pwInputType === 'password' ? 'text' : 'password')
    }

    const inputIcon = (
        <span
            className="cursor-pointer"
            onClick={(e) => onPasswordVisibleClick(e)}
        >
            {pwInputType === 'password' ? (
                <HiOutlineEyeOff />
            ) : (
                <HiOutlineEye />
            )}
        </span>
    )

    return (
        <div>
            <Input
                type={pwInputType}
                suffix={inputIcon}
                placeholder="Password"
            />
        </div>
    )
}

export default PasswordVisible

